Marathon_LGCRandom={}Marathon_LGCRandom.__index=Marathon_LGCRandom;local a=110351;local b=12345;local c=2^16-1;local function d(e,f)local g=e%c;local h=f%c;local i=0;while h>0 do if h%2~=0 then i=(i+g)%c end;g=(g+g)%c;h=math.floor(h/2)end;return i end;local function j(k)local l=1%c;local m=0;local n=a%c;local o=b%c;local p=k;while p>0 do if p%2~=0 then local q=(d(n,m)+o)%c;l=d(l,n)m=q end;local r=(d(n,o)+o)%c;n=d(n,n)o=r;p=math.floor(p/2)end;return l,m end;function Marathon_LGCRandom.New(s)local self=setmetatable({},{__index=Marathon_LGCRandom})self.seed=s or 1;self.state=self.seed%c;return self end;function Marathon_LGCRandom:JumpTo(k)k=k or 0;local t,u=j(k)self.state=(d(t,self.seed)+u)%c end;function Marathon_LGCRandom:Next()self.state=(a*self.state+b)%c end;function Marathon_LGCRandom:RandomFloat()self:Next()local v=self.state/c;return v-math.floor(v)end;function Marathon_LGCRandom:RandomInt(w,x)w=w or 0;x=x or 0;self:Next()local v=self.state/c;local y=math.floor(v*(x-w+1))+w;return y end;function Marathon_LGCRandom:RandomByWeight(z,A)if not z or#z==0 then return nil end;local B={}for C=1,#z do B[C]=A(z[C],C)end;local D=0;for C=1,#B do D=D+(B[C]or 0)end;if D<=0 then return nil end;local E=self:RandomInt(1,D)for C=1,#B do if E<=(B[C]or 0)then return z[C]end;E=E-(B[C]or 0)end;return nil end;return Marathon_LGCRandom